import { useEffect, useRef, useState } from 'react'

const AVATAR = "data:image/png;base64,"

const GREETINGS = [
  // Personal
  "Hey! I'm Amritendu 👋",
  "Throw me harder! 😄",
  "I don't break — just like my pipelines 💪",
  "Built with ❤️ by Amritendu",
  "Trek. Code. Repeat. 🏔️",
  "Uk & HP was worth every step 🏔️",

  // AI & LLM
  "I fine-tune LLMs on GPU constraints 🔬",
  "Ask me about RAG pipelines! 🧠",
  "LangChain + GPT-4 = my daily stack ⚡",
  "I speak Hinglish AND Python 🐍",
  "LoRA + 4-bit quant = 35% faster inference 📈",
  "RAG > hallucination 🎯",
  "Embeddings are just vibes in vector space 😂",

  // Projects
  "I shipped Invoice Generator to production ✅",
  "FinAxis AI indexes 92k+ doc chunks 📚",
  "WhatsApp → Ledger in milliseconds 🔁",
  "Check out my projects below! 👇",
  "I build AI for CA firms 🏦",

  // Skills flex
  "Python · LangChain · PyTorch 🛠️",
  "From WhatsApp to Power BI 📊",
  "Jenkins CI/CD? Done. 🐳",
  "Streamlit dashboards in hours ⚡",
  "Bobble AI → fine-tuning Gemma3 🤖",

  // Fun
  "Click me for more! 😄",
  "I don't just ship models — I ship outcomes 🚀",
  "Coffee + Code + Mountains ☕🏔️",
  "Available for opportunities! 📩",
  "Open to remote work 🌍",
  "Let's build something amazing! 🔥",
]

export default function FloatingMascot() {
  const SIZE = 72
  const [pos, setPos] = useState({ x: window.innerWidth - 100, y: window.innerHeight - 120 })
  const [vel, setVel] = useState({ x: -1.5, y: -1 })
  const [dragging, setDragging] = useState(false)
  const [thrown, setThrown] = useState(false)
  const [bounce, setBounce] = useState(false)
  const [greeting, setGreeting] = useState<string | null>(null)

  const dragStart = useRef({ mx: 0, my: 0, px: 0, py: 0 })
  const lastMouse = useRef({ x: 0, y: 0, t: 0 })
  const throwVel = useRef({ x: 0, y: 0 })
  const animRef = useRef<number>()
  const greetTimer = useRef<ReturnType<typeof setTimeout>>()

  function showGreeting() {
    setGreeting(GREETINGS[Math.floor(Math.random() * GREETINGS.length)])
    clearTimeout(greetTimer.current)
    greetTimer.current = setTimeout(() => setGreeting(null), 2500)
  }

  useEffect(() => {
    if (dragging || thrown) return
    let x = pos.x, y = pos.y, vx = vel.x, vy = vel.y
    function roam() {
      const W = window.innerWidth - SIZE, H = window.innerHeight - SIZE
      x += vx; y += vy
      let bounced = false
      if (x <= 0) { x = 0; vx = Math.abs(vx); bounced = true }
      if (x >= W) { x = W; vx = -Math.abs(vx); bounced = true }
      if (y <= 0) { y = 0; vy = Math.abs(vy); bounced = true }
      if (y >= H) { y = H; vy = -Math.abs(vy); bounced = true }
      if (bounced) { setBounce(true); setTimeout(() => setBounce(false), 300) }
      setPos({ x, y })
      animRef.current = requestAnimationFrame(roam)
    }
    animRef.current = requestAnimationFrame(roam)
    return () => { if (animRef.current) cancelAnimationFrame(animRef.current) }
  }, [dragging, thrown, vel])

  useEffect(() => {
    if (!thrown) return
    let x = pos.x, y = pos.y, vx = throwVel.current.x, vy = throwVel.current.y
    function throwAnim() {
      const W = window.innerWidth - SIZE, H = window.innerHeight - SIZE
      vx *= 0.97; vy = vy * 0.97 + 0.15
      x += vx; y += vy
      let bounced = false
      if (x <= 0) { x = 0; vx = Math.abs(vx) * 0.7; bounced = true }
      if (x >= W) { x = W; vx = -Math.abs(vx) * 0.7; bounced = true }
      if (y <= 0) { y = 0; vy = Math.abs(vy) * 0.7; bounced = true }
      if (y >= H) { y = H; vy = -Math.abs(vy) * 0.8; bounced = true }
      if (bounced) { setBounce(true); setTimeout(() => setBounce(false), 300); showGreeting() }
      setPos({ x, y })
      throwVel.current = { x: vx, y: vy }
      if (Math.abs(vx) < 0.3 && Math.abs(vy) < 0.3 && y >= window.innerHeight - SIZE - 2) {
        setThrown(false)
        setVel({ x: (Math.random() - 0.5) * 3, y: -1.5 })
        return
      }
      animRef.current = requestAnimationFrame(throwAnim)
    }
    animRef.current = requestAnimationFrame(throwAnim)
    return () => { if (animRef.current) cancelAnimationFrame(animRef.current) }
  }, [thrown])

  function onMouseDown(e: React.MouseEvent) {
    e.preventDefault()
    if (animRef.current) cancelAnimationFrame(animRef.current)
    setDragging(true); setThrown(false)
    dragStart.current = { mx: e.clientX, my: e.clientY, px: pos.x, py: pos.y }
    lastMouse.current = { x: e.clientX, y: e.clientY, t: Date.now() }
  }

  function onTouchStart(e: React.TouchEvent) {
    if (animRef.current) cancelAnimationFrame(animRef.current)
    setDragging(true); setThrown(false)
    const t = e.touches[0]
    dragStart.current = { mx: t.clientX, my: t.clientY, px: pos.x, py: pos.y }
    lastMouse.current = { x: t.clientX, y: t.clientY, t: Date.now() }
  }

  useEffect(() => {
    function onMouseMove(e: MouseEvent) {
      if (!dragging) return
      const nx = dragStart.current.px + (e.clientX - dragStart.current.mx)
      const ny = dragStart.current.py + (e.clientY - dragStart.current.my)
      const now = Date.now(), dt = now - lastMouse.current.t || 1
      throwVel.current = {
        x: (e.clientX - lastMouse.current.x) / dt * 16,
        y: (e.clientY - lastMouse.current.y) / dt * 16,
      }
      lastMouse.current = { x: e.clientX, y: e.clientY, t: now }
      setPos({ x: nx, y: ny })
    }
    function onTouchMove(e: TouchEvent) {
      if (!dragging) return
      const t = e.touches[0]
      const nx = dragStart.current.px + (t.clientX - dragStart.current.mx)
      const ny = dragStart.current.py + (t.clientY - dragStart.current.my)
      const now = Date.now(), dt = now - lastMouse.current.t || 1
      throwVel.current = {
        x: (t.clientX - lastMouse.current.x) / dt * 16,
        y: (t.clientY - lastMouse.current.y) / dt * 16,
      }
      lastMouse.current = { x: t.clientX, y: t.clientY, t: now }
      setPos({ x: nx, y: ny })
    }
    function onMouseUp() {
      if (!dragging) return
      setDragging(false)
      const speed = Math.sqrt(throwVel.current.x ** 2 + throwVel.current.y ** 2)
      if (speed > 2) { setThrown(true) }
      else { setVel({ x: (Math.random() - 0.5) * 3, y: -1.5 }); showGreeting() }
    }
    window.addEventListener('mousemove', onMouseMove)
    window.addEventListener('mouseup', onMouseUp)
    window.addEventListener('touchmove', onTouchMove, { passive: true })
    window.addEventListener('touchend', onMouseUp)
    return () => {
      window.removeEventListener('mousemove', onMouseMove)
      window.removeEventListener('mouseup', onMouseUp)
      window.removeEventListener('touchmove', onTouchMove)
      window.removeEventListener('touchend', onMouseUp)
    }
  }, [dragging])

  return (
    <div
      style={{
        position: 'fixed',
        left: pos.x, top: pos.y,
        width: SIZE, height: SIZE,
        zIndex: 999,
        cursor: dragging ? 'grabbing' : 'grab',
        userSelect: 'none',
        transform: bounce ? 'scale(1.3)' : dragging ? 'scale(1.1)' : 'scale(1)',
        transition: bounce ? 'transform 0.15s ease' : 'none',
        filter: dragging
          ? 'drop-shadow(0 0 16px rgba(232,160,32,0.9))'
          : 'drop-shadow(0 4px 12px rgba(0,0,0,0.6))',
      }}
      onMouseDown={onMouseDown}
      onTouchStart={onTouchStart}
      onClick={showGreeting}
    >
      {greeting && (
        <div style={{
          position: 'absolute', bottom: '110%', left: '50%',
          transform: 'translateX(-50%)',
          background: 'rgba(13,13,26,0.96)',
          border: '1px solid rgba(232,160,32,0.5)',
          color: '#F0EDE8',
          fontFamily: 'JetBrains Mono, monospace',
          fontSize: '11px', padding: '6px 12px',
          borderRadius: '6px', whiteSpace: 'nowrap',
          pointerEvents: 'none', zIndex: 1000,
        }}>
          {greeting}
          <div style={{
            position: 'absolute', top: '100%', left: '50%',
            transform: 'translateX(-50%)',
            width: 0, height: 0,
            borderLeft: '5px solid transparent',
            borderRight: '5px solid transparent',
            borderTop: '5px solid rgba(232,160,32,0.5)',
          }} />
        </div>
      )}

      <div style={{
        width: '100%', height: '100%',
        borderRadius: '50%', overflow: 'hidden',
        border: '2.5px solid rgba(232,160,32,0.8)',
        boxShadow: '0 0 20px rgba(232,160,32,0.4), 0 0 0 1px rgba(232,160,32,0.2)',
        background: '#fff',
      }}>
        <img
          src={AVATAR}
          alt="Amritendu"
          style={{
            width: '100%', height: '100%',
            objectFit: 'cover',
            objectPosition: 'center 10%',
            pointerEvents: 'none',
          }}
        />
      </div>
    </div>
  )
}